SELECT ?team ?teamLabel ?start WHERE {
  wd:Q10520 p:P54 ?statement.
  ?statement ps:P54 ?team;
             pq:P580 ?start.
  ?team rdfs:label ?teamLabel.
  FILTER(LANG(?teamLabel) = "en")
}
ORDER BY ASC(?start)
LIMIT 1

